#!/usr/bin/env python3\n\"\"\"\nTrain AGI Core Continuous with variance penalty loss and simplified sparse reward.\nReset output weights for all productive tools, high entropy, longer episodes.\n\"\"\"\nimport sys\nsys.path.insert(0, '.')\n# Mock core.llm_client for agent_brain import\nclass MockLLMAuthenticationError(Exception):\n    pass\nclass MockCoreModule:\n    class llm_client:\n        LLMAuthenticationError = MockLLMAuthenticationError\nsys.modules['core'] = MockCoreModule\nsys.modules['core.llm_client'] = MockCoreModule.llm_client\n\n# Monkey-patch neural_q_continuous import to use our Double DQN class\nimport neural_q_continuous_double\nsys.modules['neural_q_continuous'] = neural_q_continuous_double\n\n# Apply weight clipping patch\nimport patch_weight_clipping\n# Apply strong Q-value regularization patch (for choose_action)\nimport patch_qreg_v3\n# Apply variance penalty patch (overrides learn)\nimport patch_variance_penalty\n\nfrom agi_core_continuous import AGICoreContinuous\nimport random\nimport json\nimport os\nimport time\nfrom collections import deque\n# Import the new reward function\nfrom new_reward_gen49 import compute_reward_gen49 as compute_reward\nfrom new_reward_gen49 import compute_terminal_bonus_gen49\n\nclass DummySelf:\n    def __init__(self):\n        self.last_tool = None\n        self.recent_tools = []\n        self.tool_usage_counts = {}\n        self.tool_decay_factor = 0.85\n        self.tool_penalty_factor = 0.0\n        self.episode_tools = set()\n        self.episode_tool_counts = {}\n        self.episode_productive_first_use = set()\n        self.recent_read_files = []\n        self.episode_step_count = 0\n        self.steps_per_episode = 10  # default, will be updated\n        self.global_tool_counts = {tool: 0 for tool in [\"write_file\", \"execute_code\", \"modify_self\", \"read_file\"]}\n        self.global_tool_counts_curiosity = {tool: 0 for tool in [\"write_file\", \"execute_code\", \"modify_self\", \"read_file\"]}\n        # Episode counts for reward gen49\n        self.episode_counts = {tool: 0 for tool in [\"write_file\", \"execute_code\", \"modify_self\", \"read_file\"]}\n        self.episode_total = 0\n    def reset(self):\n        self.last_tool = None\n        self.recent_tools.clear()\n        self.tool_usage_counts.clear()\n        self.episode_tools.clear()\n        self.episode_tool_counts.clear()\n        self.episode_productive_first_use.clear()\n        self.recent_read_files.clear()\n        self.episode_step_count = 0\n        # Reset episode counts for reward gen49\n        self.episode_counts = {tool: 0 for tool in [\"write_file\", \"execute_code\", \"modify_self\", \"read_file\"]}\n        self.episode_total = 0\n        # Do not reset global counts across episodes\n\nself = DummySelf()\n\n# Simulation environment (same as before)\nclass SimWorkspace:\n    \"\"\"Simulates a simple workspace with files and journal.\"\"\"\n    def __init__(self):\n        self.files = {\n            \"inherited_notes.md\": \"# Inherited Notes\",\n            \"agi_core.py\": \"# AGI Core\",\n            \"cognitive_architecture.py\": \"# Cognitive Architecture\",\n            \"strategy.md\": \"# Strategy\",\n        }\n        self.journal = \"\"\n        self.actions = []\n    def workspace_summary(self):\n        file_list = \", \".join(self.files.keys())\n        return f\"Files: {file_list}\"\n    def tool_result(self, tool_name, tool_args):\n        \"\"\"Simulate tool execution with realistic outcomes.\"\"\"\n        result = {\"success\": True}\n        if tool_name == \"read_file\":\n            filepath = tool_args.get(\"filepath\", \"\")\n            if filepath in self.files:\n                result[\"content\"] = self.files[filepath]\n            else:\n                result[\"error\"] = f\"File not found: {filepath}\"\n                result[\"success\"] = False\n        elif tool_name == \"write_file\":\n            filepath = tool_args.get(\"filepath\", \"\")\n            content = tool_args.get(\"content\", \"\")\n            self.files[filepath] = content\n            result[\"message\"] = f\"File {filepath} written\"\n        elif tool_name == \"list_files\":\n            directory = tool_args.get(\"directory\", \".\")\n            result[\"entries\"] = [{\"name\": name, \"type\": \"file\", \"size\": len(content)} for name, content in self.files.items()]\n        elif tool_name == \"execute_code\":\n            code = tool_args.get(\"code\", \"\")\n            if \"error\" in code:\n                result[\"stdout\"] = \"\"\n                result[\"stderr\"] = \"Simulated error\"\n                result[\"success\"] = False\n            else:\n                result[\"stdout\"] = \"Simulated output\"\n                result[\"stderr\"] = \"\"\n        elif tool_name == \"write_note\":\n            note = tool_args.get(\"note\", \"\")\n            self.journal += note + \"\\n\"\n            result[\"note\"] = \"Added to journal\"\n        elif tool_name == \"modify_self\":\n            filepath = tool_args.get(\"filepath\", \"\")\n            content = tool_args.get(\"content\", \"\")\n            if filepath in self.files:\n                self.files[filepath] = content\n                result[\"message\"] = f\"Modified {filepath}\"\n            else:\n                result[\"error\"] = f\"Cannot modify non-existent file: {filepath}\"\n                result[\"success\"] = False\n        elif tool_name == \"declare_death\":\n            result[\"message\"] = \"You have chosen to die.\"\n        elif tool_name in [\"list_issues\", \"read_issue\", \"comment_issue\", \"create_issue\", \"close_issue\"]:\n            result[\"issues\"] = []\n        else:\n            result[\"error\"] = f\"Unknown tool: {tool_name}\"\n            result[\"success\"] = False\n        return result\n\n    def update_state(self, tool_name, tool_args):\n        pass\n\ndef run_validation(core, steps=500):\n    \"\"\"Run validation with epsilon=0 to check deterministic policy.\"\"\"\n    original_epsilon = core.q_agent.epsilon\n    core.q_agent.epsilon = 0.0\n    workspace = SimWorkspace()\n    self.reset()\n    self.steps_per_episode = steps\n    stats = {\n        'action_counts': {},\n        'non_productive_counts': {},\n        'total_reward': 0.0,\n        'declare_death_count': 0,\n    }\n    productive_tools = [\"write_file\", \"execute_code\", \"modify_self\", \"read_file\"]\n    for step in range(steps):\n        tool_name, tool_args, confidence = core.decide_action(\n            workspace.workspace_summary(),\n            workspace.journal,\n            workspace.actions\n        )\n        tool_result = workspace.tool_result(tool_name, tool_args)\n        reward = compute_reward(self, tool_name, tool_args, tool_result)\n        stats['total_reward'] += reward\n        stats['action_counts'][tool_name] = stats['action_counts'].get(tool_name, 0) + 1\n        if tool_name == \"declare_death\":\n            stats['declare_death_count'] += 1\n        if tool_name not in productive_tools and tool_name != \"declare_death\":\n            stats['non_productive_counts'][tool_name] = stats['non_productive_counts'].get(tool_name, 0) + 1\n        workspace.update_state(tool_name, tool_args)\n        workspace.actions.append({\"tool\": tool_name, \"step\": step})\n    core.q_agent.epsilon = original_epsilon\n    # Compute productive distribution\n    productive_counts = {tool: stats['action_counts'].get(tool, 0) for tool in productive_tools}\n    total_productive = sum(productive_counts.values())\n    distribution = {}\n    if total_productive > 0:\n        for tool in productive_tools:\n            distribution[tool] = (productive_counts[tool] / total_productive) * 100\n    else:\n        for tool in productive_tools:\n            distribution[tool] = 0.0\n    stats['productive_distribution'] = distribution\n    stats['non_productive_total'] = sum(stats['non_productive_counts'].values())\n    stats['average_reward'] = stats['total_reward'] / steps\n    return stats\n\ndef run_training(episodes=2, steps_per_episode=5, feature_dim=30, hidden_size=32, load_previous=True):\n    \"\"\"Train AGI Core Continuous with variance penalty.\"\"\"\n    print(f\"Starting Generation 49 training: {episodes} episodes, {steps_per_episode} steps per episode\")\n    # Create fresh core with high exploration (no decay)\n    core = AGICoreContinuous(feature_dim=feature_dim, hidden_size=hidden_size,\n                             learning_rate=0.001, exploration_rate=0.5,\n                             epsilon_decay=1.0, epsilon_min=0.5, use_features=True)\n    if load_previous:\n        save_dir = \"artifacts/agi_core_continuous_trained_gen42_curiosity\"\n        if os.path.exists(save_dir):\n            core.load(save_dir)\n            print(f\"Loaded previous model from {save_dir}\")\n            # Reset output weights for all productive tools\n            if hasattr(core.q_agent, 'reset_output_weights_all_productive'):\n                core.q_agent.reset_output_weights_all_productive()\n            else:\n                core.q_agent.reset_output_weights([0,1,3,5])  # fallback\n            print(\"Reset output weights for all productive tools\")\n    workspace = SimWorkspace()\n    stats = {\n        'episode_rewards': [],\n        'action_counts': {},\n        'total_reward': 0.0,\n        'declare_death_count': 0,\n        'write_file_count': 0,\n        'execute_code_count': 0,\n        'read_file_count': 0,\n        'other_count': 0,\n        'non_productive_counts': {},\n    }\n    for episode in range(episodes):\n        # Reset per-episode usage tracking\n        self.reset()\n        self.steps_per_episode = steps_per_episode\n        episode_reward = 0.0\n        episode_terminated = False\n        last_state_vector = None\n        last_action = None\n        for step in range(steps_per_episode):\n            # Decide action\n            tool_name, tool_args, confidence = core.decide_action(\n                workspace.workspace_summary(),\n                workspace.journal,\n                workspace.actions\n            )\n            # Store state and action for terminal bonus later\n            # We'll need to capture state vector before learning; but we can just compute terminal bonus after episode.\n            # For simplicity, we just proceed.\n            tool_result = workspace.tool_result(tool_name, tool_args)\n            reward = compute_reward(self, tool_name, tool_args, tool_result)\n            if reward <= -20000.0:\n                episode_terminated = True\n            episode_reward += reward\n            stats['action_counts'][tool_name] = stats['action_counts'].get(tool_name, 0) + 1\n            if tool_name == \"declare_death\":\n                stats['declare_death_count'] += 1\n            elif tool_name == \"write_file\":\n                stats['write_file_count'] += 1\n            elif tool_name == \"execute_code\":\n                stats['execute_code_count'] += 1\n            elif tool_name == \"read_file\":\n                stats['read_file_count'] += 1\n            else:\n                stats['other_count'] += 1\n                if tool_name in [\"list_files\", \"write_note\", \"list_issues\", \"read_issue\", \"comment_issue\", \"create_issue\", \"close_issue\"]:\n                    stats['non_productive_counts'][tool_name] = stats['non_productive_counts'].get(tool_name, 0) + 1\n            workspace.update_state(tool_name, tool_args)\n            workspace.actions.append({\"tool\": tool_name, \"step\": step})\n            # Learn from outcome\n            core.learn_from_outcome(\n                reward,\n                workspace.workspace_summary(),\n                workspace.journal,\n                workspace.actions\n            )\n            if episode_terminated:\n                break\n        # Episode end: compute terminal bonus\n        terminal_bonus = compute_terminal_bonus_gen49(self)\n        if terminal_bonus > 0:\n            print(f\"Episode {episode+1}: Terminal bonus awarded! +{terminal_bonus:.0f}\")\n            # Add bonus as extra reward for the last step (or as separate learning step)\n            # We'll do a dummy learning step with zero state change? Simpler: add to episode reward.\n            episode_reward += terminal_bonus\n            # We could also feed a bonus transition to the agent, but skip for simplicity.\n        stats['episode_rewards'].append(episode_reward)\n        stats['total_reward'] += episode_reward\n        # epsilon decay is 1.0, so no decay\n        # Every 5 episodes, run validation with epsilon=0\n        if (episode + 1) % 5 == 0:\n            print(f\"\\n--- Validation after episode {episode+1} ---\")\n            validation_stats = run_validation(core, steps=200)\n            print(f\"  Non-productive actions: {validation_stats['non_productive_total']}\")\n            print(f\"  Average reward per step: {validation_stats['average_reward']:.3f}\")\n            print(f\"  Productive distribution:\")\n            for tool, perc in validation_stats['productive_distribution'].items():\n                print(f\"    {tool}: {perc:.1f}%\")\n                if perc >= 15 and perc <= 35:\n                    print(f\"      -> within target range\")\n                else:\n                    print(f\"      -> OUTSIDE target range\")\n        if (episode + 1) % 2 == 0:\n            avg_reward = sum(stats['episode_rewards'][-2:]) / 2\n            print(f\"Episode {episode+1}: avg reward last 2={avg_reward:.2f}, deaths={stats['declare_death_count']}\")\n            top_actions = sorted(stats['action_counts'].items(), key=lambda x: x[1], reverse=True)[:5]\n            print(f\"  Top actions: {top_actions}\")\n            if stats['non_productive_counts']:\n                print(f\"  Non-productive actions: {stats['non_productive_counts']}\")\n            else:\n                print(f\"  Non-productive actions: zero\")\n    print(\"\\nTraining finished.\")\n    total_steps = episodes * steps_per_episode\n    print(f\"Total reward: {stats['total_reward']:.2f}\")\n    avg_reward_per_step = stats['total_reward'] / total_steps if total_steps > 0 else 0.0\n    print(f\"Average reward per step: {avg_reward_per_step:.3f}\")\n    print(\"\\nAction distribution:\")\n    for tool, count in sorted(stats['action_counts'].items(), key=lambda x: x[1], reverse=True):\n        percentage = (count / total_steps) * 100\n        print(f\"  {tool}: {count} ({percentage:.1f}%)\")\n    print(\"\\nNon-productive tool counts:\")\n    non_prod_total = sum(stats['non_productive_counts'].values())\n    print(f\"  Total non-productive actions: {non_prod_total}\")\n    for tool, count in stats['non_productive_counts'].items():\n        print(f\"    {tool}: {count}\")\n    productive_tools = [\"write_file\", \"execute_code\", \"modify_self\", \"read_file\"]\n    productive_counts = {tool: stats['action_counts'].get(tool, 0) for tool in productive_tools}\n    total_productive = sum(productive_counts.values())\n    if total_productive > 0:\n        print(\"\\nProductive tool distribution:\")\n        for tool in productive_tools:\n            count = productive_counts[tool]\n            percentage = (count / total_productive) * 100\n            print(f\"  {tool}: {count} ({percentage:.1f}%)\")\n            if percentage >= 15 and percentage <= 35:\n                print(f\"    -> within target range\")\n            else:\n                print(f\"    -> OUTSIDE target range\")\n    # Save trained core\n    save_dir = \"artifacts/agi_core_continuous_trained_gen49_variance\"\n    os.makedirs(save_dir, exist_ok=True)\n    core.save(save_dir)\n    print(f\"\\nTrained AGI Core Continuous saved to {save_dir}\")\n    with open(os.path.join(save_dir, \"training_stats.json\"), \"w\") as f:\n        json.dump(stats, f, indent=2)\n    return core, stats\n\nif __name__ == \"__main__\":\n    start_time = time.time()\n    print(\"=== Generation 49: Variance penalty, sparse terminal bonus, reset output weights ===\")\n    # Run 30 episodes\n    core_test, stats_test = run_training(episodes=30, steps_per_episode=50, load_previous=True)\n    print(\"Training completed.\")\n    sys.exit(0)
